// msg.payload คือ input จาก node ก่อนหน้า
msg.payload = {
    message: msg.payload,
    timestamp: new Date().toISOString(),
    from: 'Node-RED'
};
return msg;

msg.payload = { status: 'ok', message: 'pong', t: Date.now() };
msg.statusCode = 200;
return msg;

// ดึง MES_API จาก global context ที่ตั้งใน settings.js
const MES_API = global.get('MES_API') || 'http://172.16.10.87:5100';

// ดึง token จาก env (ตั้งใน .env แล้ว start node-red)
const token = env.get('MES_TOKEN') || '';

msg.url = MES_API + '/api/wo/list';
msg.headers = {
    'Authorization': 'Bearer ' + token,
    'Content-Type': 'application/json'
};
return msg;

// statusCode 200 = สำเร็จ
if (msg.statusCode !== 200) {
    node.error('MES API error: ' + msg.statusCode, msg);
    return null;
}

const wos = msg.payload.wos || [];

// นับแต่ละ status
const summary = wos.reduce((acc, wo) => {
    acc[wo.status] = (acc[wo.status] || 0) + 1;
    return acc;
}, {});

msg.payload = {
    total: wos.length,
    summary: summary,
    running: wos.filter(w => w.status === 'RUNNING'),
    fetchedAt: new Date().toISOString()
};

return msg;

const body = msg.payload;

// ตรวจว่า field สำคัญครบ
if (!body.unit_sn || !body.station || !body.result) {
    msg.payload = { error: 'missing required fields: unit_sn, station, result' };
    msg.statusCode = 400;
    node.send([null, msg]); // ส่งไป output 2 (error path)
    return;
}

// map ให้ตรงกับ MES schema
msg.mesPayload = {
    unit_sn: body.unit_sn,
    station_code: body.station,
    result: body.result,        // 'PASS' | 'FAIL'
    tested_at: body.tested_at || new Date().toISOString(),
    raw: body
};

msg.payload = { received: true };
msg.statusCode = 200;
return msg; // ส่งไป output 1 (success path)
